/**
 * Phase 7: Data-safety verification — queries Supabase for business-data counts
 * without printing any secret values.
 */
import { readFileSync } from 'node:fs';

const RENDER_API_KEY = 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs';
const RENDER_SERVICE_ID = 'srv-d7t9ivreo5us73ftose0';

async function getSupabaseCredentials(): Promise<{ url: string; serviceRoleKey: string }> {
  const resp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Accept': 'application/json' },
  });
  if (!resp.ok) throw new Error(`Render env-vars API failed: ${resp.status}`);
  const vars = await resp.json() as Array<{ envVar: { key: string; value: string } }>;

  let url = '';
  let serviceRoleKey = '';
  for (const v of vars) {
    const key = v.envVar.key;
    if (key === 'EXPO_PUBLIC_SUPABASE_URL') url = v.envVar.value;
    if (key === 'SUPABASE_SERVICE_ROLE_KEY') serviceRoleKey = v.envVar.value;
  }

  if (!url || !serviceRoleKey) throw new Error('Missing Supabase credentials on Render');
  return { url, serviceRoleKey };
}

async function countRows(url: string, key: string, table: string): Promise<number> {
  const resp = await fetch(`${url}/rest/v1/${table}?select=id`, {
    headers: {
      'apikey': key,
      'Authorization': `Bearer ${key}`,
      'Prefer': 'count=exact',
      'Range': '0-0',
    },
  });
  if (!resp.ok) {
    // Table might not exist or RLS blocks — return -1 to indicate error
    return -1;
  }
  const range = resp.headers.get('content-range');
  if (!range) return -1;
  // Format: "0-0/count" or "*/count"
  const match = range.match(/\/(\d+)/);
  return match ? parseInt(match[1], 10) : -1;
}

async function main() {
  console.log('=== Phase 7: Data-Safety Verification ===\n');

  const { url, serviceRoleKey } = await getSupabaseCredentials();
  console.log('Supabase URL: [REDACTED - loaded from Render]');
  console.log('Service Role Key: [REDACTED - loaded from Render]\n');

  // Also verify all 8 env vars are present
  const envResp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Accept': 'application/json' },
  });
  const envVars = await envResp.json() as Array<{ envVar: { key: string; value: string } }>;
  const requiredKeys = [
    'RENDER_SERVICE_ID', 'RENDER_API_KEY', 'GITHUB_TOKEN', 'GITHUB_REPO_URL',
    'OPENAI_API_KEY', 'SUPABASE_SERVICE_ROLE_KEY', 'EXPO_PUBLIC_SUPABASE_ANON_KEY', 'EXPO_PUBLIC_SUPABASE_URL',
  ];
  console.log('=== Render Env Var Audit (values redacted) ===');
  let allPresent = true;
  for (const key of requiredKeys) {
    const found = envVars.some(v => v.envVar.key === key && v.envVar.value && v.envVar.value.length > 0);
    console.log(`  ${key}: ${found ? 'PRESENT' : 'MISSING'}`);
    if (!found) allPresent = false;
  }
  console.log(`  All 8 required: ${allPresent ? 'YES' : 'NO'}\n`);

  // Count business data
  const tables = ['members', 'investors', 'buyers', 'deals', 'project_videos', 'jv_deals'];
  console.log('=== Data-Safety Counts (AFTER deploy) ===');
  const counts: Record<string, number> = {};
  for (const table of tables) {
    const count = await countRows(url, serviceRoleKey, table);
    counts[table] = count;
    console.log(`  ${table}: ${count >= 0 ? count : 'ERROR (table not accessible)'}`);
  }

  // Verify no secrets leaked
  const output = JSON.stringify(counts);
  const secretPatterns = ['ghp_', 'rnd_', 'eyJ', 'vck_', 'SUPABASE_SERVICE_ROLE'];
  let secretLeak = false;
  for (const pattern of secretPatterns) {
    if (output.includes(pattern)) {
      console.log(`  WARNING: Potential secret pattern '${pattern}' found in output!`);
      secretLeak = true;
    }
  }
  console.log(`  Secret leakage check: ${secretLeak ? 'FAILED' : 'PASSED'}\n`);

  console.log('=== Summary ===');
  console.log(`  All 8 env vars present: ${allPresent}`);
  console.log(`  No secret leakage: ${!secretLeak}`);
  console.log(`  Tables counted: ${Object.keys(counts).length}`);
}

main().catch((err) => {
  console.error('FAILED:', err.message);
  process.exit(1);
});

