/**
 * Phase 7: Data-safety verification — queries Supabase for all business-data counts
 * Uses service role key from Render (never printed).
 */
const RENDER_API_KEY = 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs';
const RENDER_SERVICE_ID = 'srv-d7t9ivreo5us73ftose0';

async function getRenderEnvVars(): Promise<Record<string, string>> {
  const resp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Accept': 'application/json' },
  });
  if (!resp.ok) throw new Error(`Render env-vars API failed: ${resp.status}`);
  const vars = await resp.json() as Array<{ envVar: { key: string; value: string } }>;
  const map: Record<string, string> = {};
  for (const v of vars) {
    map[v.envVar.key] = v.envVar.value;
  }
  return map;
}

async function countRows(url: string, key: string, table: string): Promise<number> {
  try {
    const resp = await fetch(`${url}/rest/v1/${table}?select=id&limit=1`, {
      headers: {
        'apikey': key,
        'Authorization': `Bearer ${key}`,
        'Prefer': 'count=exact',
        'Range': '0-0',
      },
    });
    if (!resp.ok) return -1;
    const range = resp.headers.get('content-range');
    if (!range) {
      // Try counting via head
      const body = await resp.json();
      if (Array.isArray(body)) return body.length;
      return -1;
    }
    const match = range.match(/\/(\d+)/);
    return match ? parseInt(match[1], 10) : -1;
  } catch {
    return -1;
  }
}

async function listTables(url: string, key: string): Promise<string[]> {
  // Query Supabase's pg_catalog via RPC
  try {
    const resp = await fetch(`${url}/rest/v1/rpc/`, {
      method: 'POST',
      headers: {
        'apikey': key,
        'Authorization': `Bearer ${key}`,
        'Content-Type': 'application/json',
      },
    });
    // This won't work generically. Let's try the OpenAPI spec instead.
  } catch {}

  // Try fetching the OpenAPI/Swagger spec which lists all tables
  try {
    const resp = await fetch(`${url}/rest/v1/`, {
      headers: {
        'apikey': key,
        'Authorization': `Bearer ${key}`,
      },
    });
    if (resp.ok) {
      const spec = await resp.json();
      // PostgREST OpenAPI spec has paths like /tablename
      const paths = Object.keys(spec.paths || {}).filter(p => p !== '/' && p !== '/rpc/');
      return paths.map(p => p.replace(/^\//, ''));
    }
  } catch {}
  return [];
}

async function main() {
  console.log('=== Phase 7: Data-Safety Verification ===\n');

  const envVars = await getRenderEnvVars();
  const supabaseUrl = envVars['EXPO_PUBLIC_SUPABASE_URL'];
  const serviceRoleKey = envVars['SUPABASE_SERVICE_ROLE_KEY'];

  if (!supabaseUrl || !serviceRoleKey) {
    throw new Error('Missing Supabase credentials on Render');
  }

  // Verify all 8 env vars
  const requiredKeys = [
    'RENDER_SERVICE_ID', 'RENDER_API_KEY', 'GITHUB_TOKEN', 'GITHUB_REPO_URL',
    'OPENAI_API_KEY', 'SUPABASE_SERVICE_ROLE_KEY', 'EXPO_PUBLIC_SUPABASE_ANON_KEY', 'EXPO_PUBLIC_SUPABASE_URL',
  ];
  console.log('=== Render Env Var Audit (values redacted) ===');
  let allPresent = true;
  for (const key of requiredKeys) {
    const found = !!envVars[key] && envVars[key].length > 0;
    console.log(`  ${key}: ${found ? 'PRESENT' : 'MISSING'}`);
    if (!found) allPresent = false;
  }
  console.log(`  All 8 required: ${allPresent ? 'YES' : 'NO'}\n`);

  // List all available tables
  console.log('=== Discovering Supabase tables ===');
  const tables = await listTables(supabaseUrl, serviceRoleKey);
  console.log(`  Found ${tables.length} tables: ${tables.slice(0, 30).join(', ')}${tables.length > 30 ? '...' : ''}\n`);

  // Count business data — try multiple possible names
  const targetTables = [
    'members', 'member', 'ivx_members',
    'investors', 'investor', 'ivx_investors',
    'buyers', 'buyer', 'ivx_buyers',
    'deals', 'deal', 'ivx_deals', 'jv_deals',
    'project_videos', 'project_video', 'ivx_project_videos',
  ];

  console.log('=== Data-Safety Counts ===');
  const counts: Record<string, number> = {};
  for (const table of targetTables) {
    const count = await countRows(supabaseUrl, serviceRoleKey, table);
    if (count >= 0) {
      counts[table] = count;
      console.log(`  ${table}: ${count}`);
    }
  }

  // Security check — no secrets in output
  const output = JSON.stringify(counts);
  const secretPatterns = ['ghp_', 'rnd_', 'eyJ', 'vck_'];
  let secretLeak = false;
  for (const pattern of secretPatterns) {
    if (output.includes(pattern)) {
      secretLeak = true;
      break;
    }
  }

  console.log('\n=== Security Verification ===');
  console.log(`  No secret leakage: ${!secretLeak ? 'PASSED' : 'FAILED'}`);
  console.log(`  All 8 env vars present: ${allPresent ? 'PASSED' : 'FAILED'}`);

  // Check that server secrets are not in EXPO_PUBLIC_ vars
  const publicVars = Object.keys(envVars).filter(k => k.startsWith('EXPO_PUBLIC_'));
  const secretInPublic = publicVars.some(k => {
    const val = envVars[k];
    return val.includes('eyJ') && k !== 'EXPO_PUBLIC_SUPABASE_ANON_KEY'; // anon key is ok
  });
  console.log(`  No server secrets in public vars: ${!secretInPublic ? 'PASSED' : 'FAILED'}`);

  console.log('\n=== Phase 7 Complete ===');
}

main().catch((err) => {
  console.error('FAILED:', err.message);
  process.exit(1);
});

